variance_code_node:
const caItems = $json.fixture.ca_items;
const contractorItems = $json.fixture.contractor_items;
const key = item => `${item.category}:${item.description}`.toLowerCase();
const caMap = Object.fromEntries(caItems.map(item => [key(item), item]));
const conMap = Object.fromEntries(contractorItems.map(item => [key(item), item]));
const keys = Array.from(new Set([...Object.keys(caMap), ...Object.keys(conMap)]));
const items = keys.map(k => {
  const ca = caMap[k];
  const con = conMap[k];
  if (ca && con) {
    const variance = ca.value === 0 ? 100 : Math.abs(con.value - ca.value) / ca.value * 100;
    const status = variance > 5 ? 'FLAG' : 'MATCH';
    return { category: ca.category, description: ca.description, ca_value: ca.value, contractor_value: con.value, unit: ca.unit, variance_pct: Number(variance.toFixed(1)), status, review_required: status !== 'MATCH' };
  }
  if (ca) return { category: ca.category, description: ca.description, ca_value: ca.value, contractor_value: null, unit: ca.unit, variance_pct: null, status: 'MISSING', review_required: true };
  return { category: con.category, description: con.description, ca_value: null, contractor_value: con.value, unit: con.unit, variance_pct: null, status: 'NEW', review_required: true };
});
return [{ json: { items, summary: { total: items.length, review_required: items.filter(i => i.review_required).length } } }];
